import React, { useState } from 'react';
import { NavLink, useRouteMatch, useLocation, useHistory } from 'react-router-dom';
import classNames from 'classnames';
import './Header.scss';

export const Header = () => {
  const [menu, setMenu] = useState('false');
  const [query, setQuery] = useState();
  const [path, setPath] = useState('/home');
  // const location = useLocation();
  // const searchParams = new URLSearchParams(location.search);
  // const applyiedQuery = searchParams.get('query') || '';
  const match = useRouteMatch();
  // const history = useHistory();
  // console.log(location);
  // console.log(match);
  // console.log(searchParams);
  // console.log(location.search);
  // console.log(history);
  // const { par = 1, ld = 2 } = match.params;
  // match.params = value;
  // console.log(match.params);
  // const { pathname } = location;
  // console.log(match, match.params);
  // const history = useHistory();
  // const val = history.location.pathname;
  // console.log(history.location.pathname);

  const categoryListFirst = ['Sports', 'World', 'Covid', 'Business'];
  const categoryListSecond = ['Politics', 'Science', 'Religion', 'Heals'];

  return (
    <header className="Header">
      <div className={classNames('container', {
        container_menu: menu,
      })}
      >
        <a href="/#logo" className="Header-Logo">News App</a>
        <div className="Header-Menu Menu">
          <ul className={classNames('Menu-List', {
            menu_visible: !menu,
          })}
          >
            <li className="Menu-Item">
              <NavLink
                to={`${path}/categories`}
                className="Menu-Link Categor"
              >
                Categories
                {}
              </NavLink>
            </li>
          </ul>
          <button
            type="button"
            className={classNames('button-menu', {
              menu_open: menu,
              menu_cross: !menu,
            })}
            onClick={() => setMenu(!menu)}
          />
        </div>
      </div>
      <div className={classNames('container-header', {
        container_tablet: !menu,
      })}
      >
        <h2 className="Header-LogoPage">News App</h2>
        <div className={classNames('container-nav', {
        })}
        >
          <form className="Header-Form form">
            <button
              type="button"
              className="button-search"
              onClick={() => setQuery('')}
            />
            <input
              type="text"
              className="form-input"
              value={query}
              onChange={e => setQuery(e.target.value)}
              placeholder="Search..."
            />
            {query && (
              <button
                type="button"
                className="button-clear"
                onClick={() => setQuery('')}
              >
                X
              </button>
            )}
          </form>
          <nav className="Header-Nav Nav">
            <NavLink
              to="/home"
              className="Nav-Link"
              onClick={() => setPath('/home')}
            >
              Home
            </NavLink>
            <NavLink
              to="/articles"
              className="Nav-Link"
              onClick={() => setPath('/articles')}
            >
              Articles
            </NavLink>
          </nav>
          <a href="http://insagram.com" className="Header-Instagram link">{}</a>
          <a href="http://twitter.com" className="Header-Twitter link">{}</a>
          <a href="http://linkedin.com" className="Header-LinkedIn link">{}</a>
        </div>
      </div>
    </header>
  );
};
